var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"이제 망했어. 다 끝났다고…….","JPN":"もう無理だ。全部おしまいだ……","ENG":"We're screwed. It's all over...","TWN":"這下完蛋了，都結束了……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"흐으윽… 나 집에 가고 싶어…….","JPN":"ううっ……家に帰りたい……","ENG":"Hngh... I wanna go home...","TWN":"嗚嗚嗚…我想回家……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"작동시킬 수도 없는 선로전환기를 계속 유지보수 할 필요가 있나?","JPN":"作動させることもできない線路転換器のメンテナンスを続ける必要があるのか？","ENG":"Is there any point in maintaining a Track Switcher we can't even power on?","TWN":"根本無法啟動的線路轉換器有必要繼續維護嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"얌전히 죽길 기다리는 건 내 성미랑 안 맞아.","JPN":"大人しく死を待つのは俺の柄じゃない。","ENG":"Sitting here waiting to die isn't my style.","TWN":"乖乖等死和我的個性不符。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"갈 때 가더라도 할 수 있는 건 전부 해봐야 속이 편하겠지.","JPN":"万一死ぬことになっても、やれることは全部やってみないと後悔するからな。","ENG":"Even if we're going down, I'd rather try everything we can first.","TWN":"就算要走也要把能做的事都試試看，心裡才會覺得舒坦。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"과연, 몸을 움직여야 나쁜 생각을 안 한다는 거군.","JPN":"なるほど、体を動かしていたほうがネガティブ思考にならないということか。","ENG":"I see. Keeping your body busy to avoid dark thoughts.","TWN":"果然要活動身體才不會有不好的念頭。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"심리적 안정감을 위한 행동이었다면 납득이 간다.","JPN":"心理的な安定のための行動なら合点がいく。","ENG":"If this is for psychological stability, that tracks.","TWN":"如果是為了得到心理上的安定而行動，那我能理解。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"분석 결과. 음악을 틀면 작업 효율이 높아진다고 하더군.","JPN":"分析結果。音楽を聞けば作業の効率が上がるらしい。","ENG":"My analysis says music raises work efficiency.","TWN":"分析結果顯示播放音樂的話會提升工作效率。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"저 바보들의 울음소리가 거슬리던 참이니, 작업에 적합한 환경을 조성해보겠다.","JPN":"ちょうどあのバカどもの鳴き声が耳障りだったし、作業に適した環境を作ってみる。","ENG":"Their bawling was annoying anyway. I'll create an optimal work ambiance.","TWN":"我正好覺得那些笨蛋的哭聲很惱人，要來打造一個適合工作的環境。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……어째 애니메이션에 나올 법한 노래 같은데.","JPN":"……なんかのアニメソングみたいだな。","ENG":"...Sounds like some anime theme.","TWN":"……怎麼感覺像是卡通裡會出現的歌？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"정확하다. 이건 최고 히트 프로그램 가면 카운터의 BGM이거든.","JPN":"その通りだ。これは最高ヒット番組仮面カウンターのBGMだからな。","ENG":"Correct. It's the BGM from the smash-hit Masked Counter.","TWN":"沒錯，這是最火紅的節目蒙面制裁者的背景音樂。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"개인적으로는 10번째 기념작인 가면 카운터 마젠타를 추천하지.","JPN":"個人的には、シリーズ10番目の記念作である「仮面カウンターマゼンタ」がおすすめだ。","ENG":"Personally, I recommend the 10th-anniversary Masked Counter Magenta.","TWN":"我個人推薦第10部紀念作品：蒙面制裁者馬真塔。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"정신 사나우니 꺼줬으면 좋겠군.","JPN":"気が散るから消してくれないか。","ENG":"Do me a favor and turn it off. It's distracting.","TWN":"真的很吵，希望你可以關掉。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"과연, 현장 분위기에 어울리지 않는 곡 선정이었나.","JPN":"そうか、現場の雰囲気に合わない選曲だったか。","ENG":"So the track didn't match the mood?","TWN":"難道是選了不符合現場氣氛的歌曲嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"그럼 장르를 변경하지. 이번에는 ASMR이다.","JPN":"ではジャンルを変更しよう。今回はASMRだ。","ENG":"Switching genres, then. It's ASMR this time.","TWN":"那就換個類型吧，這次是ASMR。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다른 소리도 집중 안되긴 마찬가지야! 심지어 마지막은 요란하잖냐!","JPN":"他の音も集中の邪魔になるのは同じだ！　しかも最後のやつはうるさいだけじゃないか！","ENG":"That's no better! And the last part's so loud!","TWN":"這也一樣沒辦法專注在其他聲音上！甚至最後還很吵雜！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"그야 실제 헬기 소리니 요란스러울 수밖에.","JPN":"それは本物のヘリの音だから仕方ない。","ENG":"Of course it's loud. That's an actual helicopter.","TWN":"那真的是直升機的聲音，所以當然很吵。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……何だと？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"상공 2400m의 고도에서 북방합의체의 것으로 추정되는 비행체를 확인했다.","JPN":"上空2400mの高度にて北方合意体のものと推定される飛行物体を確認した。","ENG":"Identified an aircraft at 2,400 meters in the air. Likely the Northern Union.","TWN":"已經確認2400公尺上空有疑似北方和議會的飛行體。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"아무래도, 얌전히 죽길 거부하는 녀석들이 제법 있는 모양이야.","JPN":"どうやら、大人しく死を待ちたくないやつらは他にも結構いるようだ。","ENG":"Seems we're not the only ones refusing to die quietly.","TWN":"看來還是有挺多不肯乖乖送死的傢伙。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"휴우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아. 이걸로 대략적인 상황 정리가 끝났군.","JPN":"よし、これであらかた状況の整理ができたな。","ENG":"Good. That roughly squares the situation.","TWN":"很好，看來情況已經整頓得差不多了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"처음엔 웬 뚱냥이가 헬기를 조종하길래 내가 침식되어버린 건가 싶었는데, 다행히 그건 아닌 모양이야.","JPN":"妙な姿のデブ猫がヘリを操縦してるものだから、自分が侵食されたのかと思ったが、そうじゃなくてよかったぜ。","ENG":"At first, when I saw a chonker flying the chopper, I thought I'd been Corrupted, but guess not.","TWN":"一開始是什麼胖貓在開直升機，我還以為被侵蝕了，但幸好不是這樣。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"걘 뚱냥이가 아니라 여우…… 아니지, 내가 무슨 말을 하는 거람.","JPN":"あいつはデブ猫じゃなくて狐……って私何言ってるんだろ。","ENG":"Fluffox is not chonky, it's a fox– Wait, what am I saying?","TWN":"牠不是胖貓，而是狐狸……不對，我在說什麼？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"어쨌든 본부 팀이 무사해서 다행이네요. IFF 신호에 응답이 없어서 최악의 상황까지 가정했거든요.","JPN":"とにかく、本部のチームが無事でよかったです。IFF信号に応答がないから、最悪の状況も考えてたんです。","ENG":"Anyway, glad HQ's intact. With no IFF reply we feared the worst.","TWN":"總之，幸好本部隊伍平安無事，因為沒有回應IFF信號，我還假設最糟的情況了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"준비도 없이 대균열에 진입하면 어쩌나 싶었는데, 지금은 문제없겠어요.","JPN":"準備もなく大亀裂に進入することになったらどうしようって思っていましたが、これなら問題ありませんね。","ENG":"I worried we'd have to dive the Grand Dimension Crevice cold, but looks like we're fine now.","TWN":"本來還在想要是毫無準備就進入大峽谷會怎麼樣，但現在應該沒問題。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"별로 대단한 건 아니야. 이쪽은 합중국에서 받은 리액터를 달아준 게 전부니까.","JPN":"別に大したものじゃない。こっちは合衆国からもらったリアクターをつけただけだ。","ENG":"We didn't do much. Just bolted on a States-issued Reactor.","TWN":"這沒什麼了不起，我們只不過是裝了從合眾國那邊得到的反應器。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런데, 그렇게 멋대로 움직여도 되는 건가?","JPN":"しかし、そんなにすぐ動いてもいいのか？","ENG":"But are you sure you should be moving around like that?","TWN":"不過可以這樣任意移動嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"내가 리액터 전문 설비기사는 아니라 다소 억지스럽게 끼워 맞춘 부분이 있어.","JPN":"俺はリアクター専門技師じゃないから、やや強引に取り付けてしまった部分もある。","ENG":"I'm no Reactor expert, but some parts were a bit forced to fit.","TWN":"因為我不是反應器專業技師，多少有些勉強加裝的部分。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"CRF 증폭으로 놀란 신경계를 가라앉히려면 뜸을 들이는 게 좋다고 보는데.","JPN":"CRF増幅で驚いた神経系を落ち着かせるために、もう少し待ったほうがいいと思うが。","ENG":"You should let your shocked nerves settle after the CRF boost.","TWN":"如果想平息因為CRF增幅而受驚的神經系統，我想還是暫緩一下比較好。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"으음-. 억지로 움직이니 근육이 파열될 것 같은 느낌이긴 하네요.","JPN":"うーん、無理やり動いたら筋肉が破裂しそうな感じではありますね。","ENG":"Mm. Feels like my muscles might tear if I push it.","TWN":"呃嗯–因為勉強移動，感覺肌肉快要破裂了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그래서 좋아! 2% 부족한 자극을 채워주는 이 짜릿함!","JPN":"でもそれがいいんです！　2％足りない刺激を満たしてくれるこの感覚！","ENG":"Which is perfect! That little extra 2% kick I've been craving!","TWN":"所以很棒！這份填補2%不足的刺激感！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……뭐, 실전성은 충분하니 괜찮겠지.","JPN":"……ま、実際問題がないなら大丈夫だろう。","ENG":"...Well, if it works in the field, who am I to argue.","TWN":"……嗯，實戰性已經足夠，應該沒問題。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};